Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "data": { "name": "dataset" },
  "height": 290,
  "title": {
    "text": "Category Mix Shift",
    "subtitle": [
      "Revenue share by category, before vs. after COVID onset",
      "DIY / Home Improvement excluded - its swing reflects a Dec 2019 taxonomy reclassification, not a COVID effect"
    ],
    "anchor": "start",
    "color": "#666666",
    "subtitleColor": "#666666",
    "fontSize": 22,
    "fontWeight": "normal",
    "subtitleFontSize": 12,
    "offset": 24
  },
  "transform": [
    { "fold": ["PreCovidSharePct", "CovidSharePct"], "as": ["Period", "SharePct"] },
    { "calculate": "datum.Period === ''PreCovidSharePct'' ? ''Pre-COVID'' : ''COVID Onset''", "as": "PeriodLabel" }
  ],
  "layer": [
    {
      "mark": { "type": "line", "point": true, "strokeWidth": 2 },
      "encoding": {
        "x": { "field": "PeriodLabel", "type": "ordinal", "sort": ["Pre-COVID", "COVID Onset"], "title": null },
        "y": { "field": "SharePct", "type": "quantitative", "title": "Revenue Share", "axis": { "format": "%" } },
        "detail": { "field": "DisplayName" },
        "color": {
          "field": "DisplayName", "type": "nominal", "legend": null,
          "scale": {
            "domain": ["Apparel", "Appliances", "Computers & Peripherals", "Electronics", "Sports & Outdoor", "Unknown / No Category"],
            "range": ["#70B0E0", "#FCB714", "#0EB194", "#2878BD", "#AF916D", "#7F8C8D"]
          }
        },
        "tooltip": [
          { "field": "DisplayName", "type": "nominal", "title": "Category" },
          { "field": "PeriodLabel", "type": "nominal", "title": "Period" },
          { "field": "SharePct", "type": "quantitative", "format": ".1%", "title": "Revenue Share" }
        ]
      }
    },
    {
      "mark": { "type": "text", "align": "left", "dx": 8, "fontSize": 11 },
      "transform": [
        { "filter": "datum.PeriodLabel === ''COVID Onset''" },
        {
          "calculate": "datum.DisplayName === ''Computers & Peripherals'' ? 0.005 : datum.DisplayName === ''Sports & Outdoor'' ? 0.022 : datum.DisplayName === ''Unknown / No Category'' ? 0.040 : datum.DisplayName === ''Apparel'' ? 0.058 : datum.SharePct",
          "as": "LabelY"
        }
      ],
      "encoding": {
        "x": { "field": "PeriodLabel", "type": "ordinal", "sort": ["Pre-COVID", "COVID Onset"] },
        "y": { "field": "LabelY", "type": "quantitative" },
        "text": { "field": "DisplayName" },
        "color": {
          "field": "DisplayName", "type": "nominal", "legend": null,
          "scale": {
            "domain": ["Apparel", "Appliances", "Computers & Peripherals", "Electronics", "Sports & Outdoor", "Unknown / No Category"],
            "range": ["#70B0E0", "#FCB714", "#0EB194", "#2878BD", "#AF916D", "#7F8C8D"]
          }
        }
      }
    }
  ]
}'
